def search_keyword(
    path: str, keyword: str, excludes: list[str] | None = None
):
    path = _normalize_path(path)
    print(f"正在搜索关键词: {keyword} ")
    results = []
    excludes = excludes or []
    root = _resolve_path(path)

    for file in root.rglob("*"):
        if not file.is_file():
            continue

        file_path = str(file)
        path_parts = {part.lower() for part in file.parts}
        if any(
            exclude.lower() in file_path.lower() or exclude.lower() in path_parts
            for exclude in excludes
        ):
            continue

        try:
            text = file.read_text(encoding="utf-8")
        except Exception:
            continue

        if keyword in text:
            results.append(file_path)

    print(f"在{results}中搜索到关键词：{keyword}")
    return {
        "path": path,
        "keyword": keyword,
        "excludes": excludes,
        "content": results,
    }


